+function hashArgs(args: string[]): string {
+  let hash = 2166136261;
+  for (const arg of args) {
+    for (let i = 0; i < arg.length; i++) {
+      hash ^= arg.charCodeAt(i);
+      hash = (hash * 16777619) >>> 0;
+    }
+    hash ^= 0xff; // separator
+  }
+  return hash.toString(36);
