+  /**
+   * Schedule an update (debounced)
+   */
+  update(value: T): void {
+    this.pending = value;
+
+    const now = Date.now();
+    const timeSinceLastEmit = now - this.lastEmitTime;
+
+    // If enough time has passed, emit immediately
+    if (timeSinceLastEmit >= this.debounceMs) {
+      this.flush();
+      return;
+    }
+
+    // Otherwise, schedule for later
+    if (!this.timeoutId) {
+      this.timeoutId = setTimeout(() => {
+        this.flush();
+      }, this.debounceMs - timeSinceLastEmit);
+    }
+  }
+
+  /**
+   * Flush pending update immediately
+   */
+  flush(): void {
+    if (this.timeoutId) {
+      clearTimeout(this.timeoutId);
+      this.timeoutId = null;
+    }
+
+    if (this.pending !== null) {
+      this.emit(this.pending);
+      this.pending = null;
+      this.lastEmitTime = Date.now();
+    }
+  }
+
+  /**
+   * Cancel pending update
+   */
+  cancel(): void {
+    if (this.timeoutId) {
+      clearTimeout(this.timeoutId);
+      this.timeoutId = null;
+    }
+    this.pending = null;
+  }
+}
+
+// ============================================================================
+// Lazy Parser - Parse on Access
+// ============================================================================
+
+/**
+ * Lazy value wrapper - computes value on first access
+ */
+export class Lazy<T> {
+  private computed = false;
+  private value: T | undefined;
+  private error: Error | undefined;
+
+  constructor(private readonly factory: () => T) {}
+
+  /**
+   * Get the value (computes on first access)
+   */
+  get(): T {
+    if (!this.computed) {
+      try {
+        this.value = this.factory();
+      } catch (e) {
+        this.error = e as Error;
+      }
+      this.computed = true;
+    }
+
+    if (this.error) {
+      throw this.error;
+    }
+
+    return this.value!;
+  }
+
+  /**
+   * Check if value has been computed
+   */
+  get isComputed(): boolean {
+    return this.computed;
+  }
+
+  /**
+   * Reset to uncomputed state
+   */
+  reset(): void {
+    this.computed = false;
+    this.value = undefined;
+    this.error = undefined;
+  }
