+/**
+ * Async lazy value wrapper
+ */
+export class AsyncLazy<T> {
+  private promise: Promise<T> | null = null;
+  private value: T | undefined;
+  private resolved = false;
+
+  constructor(private readonly factory: () => Promise<T>) {}
