+    return this.promise;
+  }
+
+  /**
+   * Check if value has been resolved
+   */
+  get isResolved(): boolean {
+    return this.resolved;
+  }
+
+  /**
+   * Reset to uncomputed state
+   */
+  reset(): void {
+    this.promise = null;
+    this.value = undefined;
+    this.resolved = false;
+  }
+}
