+
+  state.config = {
+    memoryLimit: config?.memoryLimit ?? 10 * 1024 * 1024, // 10MB default
+    autoCleanup: config?.autoCleanup ?? true,
+    preWarmPools: config?.preWarmPools ?? false,
+    pollInterval: config?.pollInterval ?? 5000,
+  };
