+
+  state.initialized = true;
+  console.log('[memory] Memory system initialized', {
+    limit: `${(state.config.memoryLimit! / (1024 * 1024)).toFixed(2)}MB`,
+    autoCleanup: state.config.autoCleanup,
+    preWarmed: state.config.preWarmPools,
